<?phpnamespace App\Controller;use App\Entity\SysAdminOperation;use App\Entity\TypeDocumentPropriete;use App\Form\TypeDocumentProprieteType;use App\Repository\TypeDocumentProprieteRepository;use DateTime;use DateTimeZone;use Exception;use Sensio\Bundle\FrameworkExtraBundle\Configuration\Security;use Symfony\Bundle\FrameworkBundle\Controller\AbstractController;use Symfony\Component\HttpFoundation\JsonResponse;use Symfony\Component\HttpFoundation\Request;use Symfony\Component\HttpFoundation\Response;use Symfony\Component\Routing\Annotation\Route;class TypeDocumentProprieteController extends AbstractController{    /**     * @Security("is_granted('ROLE_SUPER_ADMIN') and user.getIsActived() and user.getIsKohUser() and user.getIsConfirmed()")     * @Route("/super_admin/type_document_proprietes", name="type_document_propriete_index", methods={"GET"})     * @param TypeDocumentProprieteRepository $typeDocumentProprieteRepository     * @return Response     */    public function index(TypeDocumentProprieteRepository $typeDocumentProprieteRepository): Response    {        return $this->render('type_document_propriete/index.html.twig', [            'type_document_proprietes' => $typeDocumentProprieteRepository->findAll(),        ]);    }    /**     * @Security("is_granted('ROLE_SUPER_ADMIN') and user.getIsActived() and user.getIsKohUser() and user.getIsConfirmed() and user.getIsAdmin()")     * @Route("/super-admin/type-document-proprietes/new", name="type_document_propriete_new", methods={"GET","POST"})     * @param Request $request     * @return Response     * @throws Exception     */    public function new(Request $request): Response    {        $typeDocumentPropriete = new TypeDocumentPropriete();        $form = $this->createForm(TypeDocumentProprieteType::class, $typeDocumentPropriete);        $form->handleRequest($request);        if ($form->isSubmitted() && $form->isValid()) {            $entityManager = $this->getDoctrine()->getManager();            $entityManager->persist($typeDocumentPropriete);            $entityManager->flush();            $this->addFlash('success', 'Le type de document de proprieté a été enregistré');            $sysOp = new SysAdminOperation();            $sysOp->setCreatedAt(new DateTime('now', new DateTimeZone('GMT')))                ->setKohUtilisateur($this->getUser())                ->setDescription('Enregistrement type document de propriété')                ->setUserAffected($typeDocumentPropriete->getName());            $this->getDoctrine()->getManager()->persist($sysOp);            $this->getDoctrine()->getManager()->flush();            return $this->redirectToRoute('type_document_propriete_index');        }        return $this->render('type_document_propriete/new.html.twig', [            'type_document_propriete' => $typeDocumentPropriete,            'form' => $form->createView(),        ]);    }    /**     * @Security("is_granted('ROLE_SUPER_ADMIN') and user.getIsActived() and user.getIsKohUser() and user.getIsConfirmed()")     * @Route("/super-admin/type-document-proprietes/{id}", name="type_document_propriete_show", methods={"GET"})     * @param TypeDocumentPropriete $typeDocumentPropriete     * @return Response     */    public function show(TypeDocumentPropriete $typeDocumentPropriete): Response    {        return $this->render('type_document_propriete/show.html.twig', [            'type_document_propriete' => $typeDocumentPropriete,        ]);    }    /**     * @Security("is_granted('ROLE_SUPER_ADMIN') and user.getIsActived() and user.getIsKohUser() and user.getIsConfirmed() and user.getIsAdmin()")     * @Route("/super-admin/type-document-proprietes/{id}/edit", name="type_document_propriete_edit", methods={"GET","POST"})     * @param Request $request     * @param TypeDocumentPropriete $typeDocumentPropriete     * @return Response     * @throws Exception     */    public function edit(Request $request, TypeDocumentPropriete $typeDocumentPropriete): Response    {        $form = $this->createForm(TypeDocumentProprieteType::class, $typeDocumentPropriete);        $form->handleRequest($request);        if ($form->isSubmitted() && $form->isValid()) {            $this->getDoctrine()->getManager()->flush();            $this->addFlash('success', 'Le type de document de proprieté a été modifié');            $sysOp = new SysAdminOperation();            $sysOp->setCreatedAt(new DateTime('now', new DateTimeZone('GMT')))                ->setKohUtilisateur($this->getUser())                ->setDescription('Modification type document de propriété')                ->setUserAffected($typeDocumentPropriete->getName());            $this->getDoctrine()->getManager()->persist($sysOp);            $this->getDoctrine()->getManager()->flush();            return $this->redirectToRoute('type_document_propriete_index');        }        return $this->render('type_document_propriete/edit.html.twig', [            'type_document_propriete' => $typeDocumentPropriete,            'form' => $form->createView(),        ]);    }    /**     * @Security("is_granted('ROLE_SUPER_ADMIN') and user.getIsActived() and user.getIsKohUser() and user.getIsConfirmed() and user.getIsAdmin()")     * @Route("/super-admin/type-document-proprietes/{id}", name="type_document_propriete_delete", methods={"DELETE"})     * @param Request $request     * @param TypeDocumentPropriete $typeDocumentPropriete     * @return Response     * @throws Exception     */    public function delete(Request $request, TypeDocumentPropriete $typeDocumentPropriete): Response    {        if ($this->isCsrfTokenValid('delete' . $typeDocumentPropriete->getId(), $request->request->get('_token'))) {            $entityManager = $this->getDoctrine()->getManager();            $entityManager->remove($typeDocumentPropriete);            $entityManager->flush();            $this->addFlash('success', 'Le type de document de proprieté a été supprimé');            $sysOp = new SysAdminOperation();            $sysOp->setCreatedAt(new DateTime('now', new DateTimeZone('GMT')))                ->setKohUtilisateur($this->getUser())                ->setDescription('Suppression type de document de propriéte')                ->setUserAffected($typeDocumentPropriete->getName());            $this->getDoctrine()->getManager()->persist($sysOp);            $this->getDoctrine()->getManager()->flush();        }        return $this->redirectToRoute('type_document_propriete_index');    }    /**     * @Route("/koh_archivage/admin/type_documents/get_type_document")     * @param TypeDocumentProprieteRepository $documentRepository     * @return JsonResponse     */    public function loadTypeDocument(TypeDocumentProprieteRepository $documentRepository): JsonResponse    {        $types = $documentRepository->findAll();        $array_type = array();        foreach ($types as $type) {            $t = array(                'id' => $type->getId(),                'libelle' => $type->getName()            );            $array_type[] = $t;        }        return new JsonResponse($array_type, 200);    }}